<template>
  <div class="dashboard-header">
    <!-- Left: Date & Time -->
    <div class="datetime-table-left">
      <table class="datetime-table">
        <tr>
          <td class="datetime-label">DATE :-</td>
          <td class="datetime-value">{{ currentDate }}</td>
        </tr>
        <tr>
          <td class="datetime-label">TIME :-</td>
          <td class="datetime-value">{{ currentTime }}</td>
        </tr>
      </table>
    </div>


    <!-- TOYOTA BOSHOKU LOGO & NAME - Operating Status से पहले add करें -->
<div class="company-info-section">
  <!-- LOGO -->
  <div class="tb-logo">
   <img class="tb-logo" src="data:image/png;base64," alt="Logo">

  </div>
 
  <!-- COMPANY NAME -->
  <div class="company-name">
    <div class="main-title">TOYOTA BOSHOKU DEVICE INDIA </div>
    <div class="sub-title">Production Dashboard</div>
  </div>
 
</div>
    <!-- Middle: Operating Status -->
   

    <!-- Right: Current Shift -->
    <div class="shift-only-right">
      <div class="shift-container">
        <div class="shift-label">CURRENT SHIFT</div>
        <div class="shift-value-large" :style="{ color: shiftColor }">
          {{ currentShift }}
        </div>
      </div>
    </div>
  </div>
</template>

<script setup>
import { ref, computed, onMounted, onUnmounted } from 'vue'

const props = defineProps({
  operatingStatus: {
    type: String,
    default: 'RUNNING'
  }
})

// Reactive data
const currentDate = ref('')
const currentTime = ref('')
const currentShift = ref('A')

// Computed properties
const statusClass = computed(() => {
  const status = props.operatingStatus.toLowerCase()
  return `status-${status}`
})

const shiftColor = computed(() => {
  return '#ebff3bff'
})

// Update date and time
function updateDateTime() {
  const now = new Date()
 
  // Format date as DD/MM/YYYY
  const day = now.getDate().toString().padStart(2, '0')
  const month = (now.getMonth() + 1).toString().padStart(2, '0')
  const year = now.getFullYear()
  currentDate.value = `${day}/${month}/${year}`
 
  // Format time as HH:MM:SS AM/PM
  let hours = now.getHours()
  const minutes = now.getMinutes().toString().padStart(2, '0')
  const seconds = now.getSeconds().toString().padStart(2, '0')
  const ampm = hours >= 12 ? 'PM' : 'AM'
  hours = hours % 12
  hours = hours ? hours : 12
  currentTime.value = `${hours.toString().padStart(2, '0')}:${minutes}:${seconds} ${ampm}`
}

// Auto shift detection
function detectShift() {
  const now = new Date()
  const hour = now.getHours()
  const minute = now.getMinutes()
  const totalMinutes = (hour * 60) + minute
 
  // A Shift: 08:30 to 17:30
  const aStart = (8 * 60) + 30
  const aEnd = (17 * 60) + 30
 
  // B Shift: 18:30 to 03:30 (next day)
  const bStart = (18 * 60) + 30
  const bEnd = (3 * 60) + 30
 
  if (totalMinutes >= aStart && totalMinutes <= aEnd) {
    currentShift.value = 'A'
  } else if (totalMinutes >= bStart || totalMinutes <= bEnd) {
    currentShift.value = 'B'
  } else {
    currentShift.value = '-'
  }
}

// Lifecycle hooks
onMounted(() => {
  updateDateTime()
  detectShift()
 
  const dateTimeInterval = setInterval(updateDateTime, 1000)
  const shiftInterval = setInterval(detectShift, 60000)
 
  onUnmounted(() => {
    clearInterval(dateTimeInterval)
    clearInterval(shiftInterval)
  })
})
</script>

